import React, {useEffect, useState} from "react";
import Navbar from "./Navbar";
import Intro from "./Intro";
import AboutMe from "./AboutMe";
import Projects from "./Projects";
import ScrollToTop from "./ScrollToTop";
import Contact from "./Contact";
import {Route} from "react-router-dom";
import { useLocation } from 'react-router-dom';

const Profession = () => {
    const location = useLocation();
    const [isProfession,SetProfession] = useState({
        web:false,
        software:false,
        ml:false
    });
    useEffect(()=>{

        if(location.state.prof === "web")
        {
            SetProfession({web:true});
        } else if (location.state.prof === "software")
        {
            SetProfession({software:true});
        } else
        {
            SetProfession({ml:true});
        }
        alert(isProfession.web);

    },[location]);
    return (
        <div>
            <Navbar/>
            <Intro {...isProfession}/>
            <AboutMe {...isProfession}/>
            <Projects {...isProfession}/>
            <ScrollToTop/>
            <Contact/>
        </div>
    );
};
export default Profession;
